arguments.file_text:
@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]

@inject IShipmentService ShipmentService

<PageTitle>Shipments Dashboard</PageTitle>

<h1>Shipments Dashboard</h1>

<div class="d-flex justify-content-between align-items-center mb-3">
    <div>
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <button class="btn btn-success" @onclick="ShowCreateForm">
        + New Shipment
    </button>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Create New Shipment</h5>
            <div class="row g-3">
                <div class="col-md-4">
                    <label class="form-label">Origin</label>
                    <input type="text" class="form-control" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Destination</label>
                    <input type="text" class="form-control" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Customer Email</label>
                    <input type="email" class="form-control" @bind="newShipment.CustomerEmail" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Description</label>
                    <input type="text" class="form-control" @bind="newShipment.Description" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Estimated Delivery</label>
                    <input type="date" class="form-control" @bind="estimatedDeliveryDate" />
                </div>
                <div class="col-md-3 d-flex align-items-end gap-2">
                    <button class="btn btn-primary" @onclick="CreateShipment" disabled="@isCreating">
                        @(isCreating ? "Creating..." : "Create")
                    </button>
                    <button class="btn btn-secondary" @onclick="CancelCreate">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

@if (shipments == null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Customer</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                        <td>@shipment.CustomerEmail</td>
                        <td>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                    value="@shipment.Status"
                                    @onchange="(e) => UpdateStatus(shipment, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private bool showCreateForm;
    private bool isCreating;
    private CreateShipmentRequest newShipment = new();
    private DateTime? estimatedDeliveryDate;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s => string.IsNullOrEmpty(filterText)
            || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)
            || s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm() => showCreateForm = true;
    private void CancelCreate()
    {
        showCreateForm = false;
        newShipment = new();
        estimatedDeliveryDate = null;
    }

    private async Task CreateShipment()
    {
        isCreating = true;
        newShipment.EstimatedDelivery = estimatedDeliveryDate;
        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        shipments?.Insert(0, created);
        CancelCreate();
        isCreating = false;
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services

@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mt-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isTracking">
                @(isTracking ? "Searching..." : "Track")
            </button>
        </div>
    </div>
</div>

@if (result is not null)
{
    @if (result.Found)
    {
        <div class="card mt-4">
            <div class="card-body">
                <h5 class="card-title">Shipment: <code>@result.TrackingNumber</code></h5>
                <div class="row mt-3">
                    <div class="col-md-3">
                        <strong>Status</strong>
                        <p><span class="badge @GetStatusBadgeClass(result.Status) fs-6">@result.Status</span></p>
                    </div>
                    <div class="col-md-3">
                        <strong>Destination</strong>
                        <p>@result.Destination</p>
                    </div>
                    <div class="col-md-3">
                        <strong>Estimated Delivery</strong>
                        <p>@(result.EstimatedDelivery?.ToString("MMMM dd, yyyy") ?? "Not available")</p>
                    </div>
                    <div class="col-md-3">
                        <strong>Description</strong>
                        <p>@(string.IsNullOrEmpty(result.Description) ? "—" : result.Description)</p>
                    </div>
                </div>

                <div class="mt-3">
                    <h6>Delivery Progress</h6>
                    <div class="progress" style="height: 25px;">
                        <div class="progress-bar @GetProgressBarClass(result.Status)"
                             role="progressbar"
                             style="width: @(GetProgressPercent(result.Status))%">
                            @result.Status
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
    else
    {
        <div class="alert alert-warning mt-4">
            No shipment found with tracking number "<strong>@trackingNumber</strong>". Please check the number and try again.
        </div>
    }
}

@code {
    private string trackingNumber = string.Empty;
    private TrackingResult? result;
    private bool isTracking;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        isTracking = true;
        result = await ShipmentService.TrackShipmentAsync(trackingNumber.Trim());
        isTracking = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };
}

