using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await db.Shipments
            .OrderByDescending(s => s.CreatedAt)
            .Select(s => ToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentAsync(int id)
    {
        var shipment = await db.Shipments.FindAsync(id);
        return shipment is null ? null : ToDto(shipment);
    }

    public async Task<TrackingResult> TrackShipmentAsync(string trackingNumber)
    {
        var shipment = await db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);

        if (shipment is null)
            return new TrackingResult { Found = false };

        return new TrackingResult
        {
            TrackingNumber = shipment.TrackingNumber,
            Status = shipment.Status,
            Destination = shipment.Destination,
            EstimatedDelivery = shipment.EstimatedDelivery,
            Description = shipment.Description,
            Found = true
        };
    }

    public async Task<ShipmentDto> CreateShipmentAsync(CreateShipmentRequest request)
    {
        var shipment = new Shipment
        {
            TrackingNumber = GenerateTrackingNumber(),
            Origin = request.Origin,
            Destination = request.Destination,
            CustomerEmail = request.CustomerEmail,
            Description = request.Description,
            EstimatedDelivery = request.EstimatedDelivery,
            Status = ShipmentStatus.Pending,
            CreatedAt = DateTime.UtcNow
        };

        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return ToDto(shipment);
    }

    public async Task UpdateStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is not null)
        {
            shipment.Status = status;
            await db.SaveChangesAsync();
        }
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status,
        CreatedAt = s.CreatedAt,
        EstimatedDelivery = s.EstimatedDelivery,
        CustomerEmail = s.CustomerEmail,
        Description = s.Description
    };

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100000, 999999)}";
    }
}

