using Microsoft.AspNetCore.Http.HttpResults;
using Microsoft.AspNetCore.Mvc;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("/", async (IShipmentService service) =>
            await service.GetAllShipmentsAsync());

        group.MapGet("/{id:int}", async (int id, IShipmentService service) =>
        {
            var shipment = await service.GetShipmentAsync(id);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        // Tracking endpoint is public — customers don't need to log in
        app.MapGet("api/shipments/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
            await service.TrackShipmentAsync(trackingNumber));

        group.MapPost("/", async (CreateShipmentRequest request, IShipmentService service) =>
        {
            var created = await service.CreateShipmentAsync(request);
            return Results.Created($"api/shipments/{created.Id}", created);
        });

        group.MapPut("/{id:int}/status", async (int id, [FromBody] StatusUpdateRequest request, IShipmentService service) =>
        {
            await service.UpdateStatusAsync(id, request.Status);
            return Results.NoContent();
        });
    }
}

public record StatusUpdateRequest(ShipmentStatus Status);

